from flask import Flask, request, jsonify
import pickle
import os

app = Flask(__name__)

# Directory to store uploaded models
UPLOAD_FOLDER = 'models'
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)

@app.route('/upload_model', methods=['POST'])
def upload_model():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file_path = os.path.join(UPLOAD_FOLDER, filename)
        file.save(file_path)
        
        try:
            with open(file_path, 'rb') as f:
                model = pickle.load(f)
            return jsonify({'message': 'Model uploaded and loaded successfully'}), 200
        except Exception as e:
            os.remove(file_path)  # Remove the file if loading fails
            return jsonify({'error': str(e)}), 500

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() == 'pkl'

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)